<?php require '../db_connection.php'; header('Content-Type: application/json'); if (isset($_GET['course_id'])) { $stmt = $db->prepare('SELECT MIN(id) as id, chapter, topic_name FROM main_topics WHERE course_id = ? GROUP BY chapter, topic_name ORDER BY chapter ASC'); $stmt->execute([$_GET['course_id']]); echo json_encode($stmt->fetchAll(PDO::FETCH_ASSOC)); } else { echo json_encode([]); } ?>
